const matchTemplatesByProfile = `-- name: MatchTemplatesByProfile :many
SELECT
    t.id, t.template_name, t.category, t.display_name, t.description, t.icon_type, t.target_business_types, t.target_challenges, t.target_team_sizes, t.priority_score, t.template_config, t.required_modules, t.optional_features, t.generation_prompt, t.scaffold_type, t.created_at, t.updated_at,
    -- Calculate matching score
    CASE
        WHEN $1::text = ANY(t.target_business_types) THEN 40
        ELSE 0
    END +
    CASE
        WHEN $2::text = ANY(t.target_challenges) THEN 30
        ELSE 0
    END +
    CASE
        WHEN $3::text = ANY(t.target_team_sizes) THEN 20
        ELSE 0
    END +
    t.priority_score as match_score
FROM app_templates t
WHERE
    $1::text = ANY(t.target_business_types)
    OR $2::text = ANY(t.target_challenges)
    OR $3::text = ANY(t.target_team_sizes)
ORDER BY match_score DESC
LIMIT $4
`

type MatchTemplatesByProfileParams struct {
	Column1 string `json:"column_1"`
	Column2 string `json:"column_2"`
	Column3 string `json:"column_3"`
	Limit   int32  `json:"limit"`
}

